local setting = MonsterSetting.new()
setting.monsterId = 1
setting.monsterBtTree = "EmptyAI"
setting.monsterType = 2
HostApi.addMonsterSetting(setting)
ServerHelper.putBoolPrefs("IsCreatureCollision", false)
ServerHelper.putIntPrefs("CreatureAISyncMoveTicks", 1000000000)

ServerMonster = class("ServerMonster", BaseBtTree)

function ServerMonster:ctor(position, actor, config, ...)
    self.type = config.type
    self.frameInterval = config.frameInterval or 1000
    self.curFrameInterval = 0
    self.realSpeed = config.patrolSpeed or 2
    self.speed = self.realSpeed / (1000 / self.frameInterval)
    self.curPos = position
    self.curPath = {}
    self.canMoveDis = 0
    self.lockMove = false
    self.teamId = 1
    self.hp = config.hp
    self.entityId = EngineWorld:addCreatureNpc(position, 1, 0, actor, function(entity)
        self.entity = entity
        self.entity:setCanFly(true)
    end)
    self:onCreate(config, ...)
    MonsterManager:addMonster(self)
    GamePacketSender:sendMonsterHP(self.entityId, self.hp)
    self:setCountdownToDeath(config.lifeTime)
end

function ServerMonster:onCreate(...)

end

---设置怪物的速度
function ServerMonster:setSpeed(speed)
    if self.realSpeed ~= speed then
        self.realSpeed = speed
        self.speed = self.realSpeed / (1000 / self.frameInterval)
        GamePacketSender:sendMonsterSpeed(self.entityId, self.speed)
    end
end

---设置逻辑帧间隔
function ServerMonster:setFrameTime(frameInterval)
    self.frameInterval = frameInterval
    self.speed = self.realSpeed / (1000 / self.frameInterval)
    GamePacketSender:sendFrameInterval(self.entityId, self.frameInterval)
end

function ServerMonster:onUpdate()
    self.curFrameInterval = self.curFrameInterval + 100
    if self.curFrameInterval < self.frameInterval then
        return
    end
    self.curFrameInterval = self.curFrameInterval - self.frameInterval
    if EngineWorld:getEntity(self.entityId) == nil then
        self:setDead()
        return
    end
    self:onMoveUpdate()
    self:onLogicUpdate()
end

local function canMove(position)
    for offsetY = 1, 5 do
        if EngineWorld:getBlockId(VectorUtil.getNegY(position, offsetY)) ~= 0 then
            return true
        end
    end
    return false
end

function ServerMonster:onMoveUpdate()
    if self.lockMove then
        self.lockMove = false
        return
    end
    if #self.curPath == 0 and self.toPos ~= nil then
        self.curPath = BtUtil.getCurPath(self.entity.position, self.toPos)
        if #self.curPath <= 2 then
            self.curPath = {}
            self.toPos = nil
        else
            table.remove(self.curPath, 1)
        end
    end
    self.canMoveDis = self.canMoveDis + self.speed
    local needSync = false
    local position
    while self.canMoveDis > 0 and #self.curPath > 0 do
        self.canMoveDis = self.canMoveDis - 1
        position = self.curPath[#self.curPath]
        if not canMove(position) then
            self.curPath = {}
            self.toPos = nil
            return
        end
        needSync = true
        if #self.curPath > 1 then
            local nextPos = self.curPath[#self.curPath - 1]
            if position.y ~= nextPos.y then
                self.curPath = {}
                self.lockMove = true
                position.x = position.x + 0.5
                position.z = position.z + 0.5
                GamePacketSender:sendMonsterPosition(self.entityId, position)
                if nextPos.y > position.y and EngineWorld:getBlockId(VectorUtil.getNegY(nextPos)) ~= 0 then
                    position.y = nextPos.y
                    GamePacketSender:sendMonsterPosition(self.entityId, position, true)
                end
                if nextPos.y < position.y and EngineWorld:getBlockId(VectorUtil.getPosY(nextPos)) == 0 then
                    local oldPos = TableUtil.copyTable(nextPos)
                    nextPos.x = nextPos.x + 0.5
                    nextPos.z = nextPos.z + 0.5
                    nextPos.y = position.y
                    GamePacketSender:sendMonsterPosition(self.entityId, nextPos, true)
                    nextPos = oldPos
                end
                nextPos.x = nextPos.x + 0.5
                nextPos.z = nextPos.z + 0.5
                GamePacketSender:sendMonsterPosition(self.entityId, nextPos)
                self.entity:setPosition(nextPos)
                return
            end
        end
        table.remove(self.curPath, #self.curPath)
    end
    if needSync then
        position.x = position.x + 0.5
        position.z = position.z + 0.5
        self.entity:setPosition(position)
        GamePacketSender:sendMonsterPosition(self.entityId, position)
    end
end

---业务逻辑层处理，可以写追击目标逻辑，攻击逻辑
function ServerMonster:onLogicUpdate()

end

function ServerMonster:setDead()
    self.entity = nil
    MonsterManager:removeMonster(self)
    GamePacketSender:sendMonsterDie(self.entityId)
    LuaTimer:schedule(function()
        EngineWorld:removeEntity(self.entityId)
    end, 2000)
end

---设置怪物存活时间
function ServerMonster:setCountdownToDeath(time)
    GamePacketSender:sendMonsterCountdown(self.entityId, time)
    self.deathTimeKey = LuaTimer:schedule(function()
        self:setDead()
    end, time * 1000)
end

---设置怪物去某个坐标
function ServerMonster:tryToPosition(position)
    self.toPos = position
end

---播放怪物动作，不包括run和idle
function ServerMonster:playAction(action)
    GamePacketSender:sendMonsterAction(self.entityId, action)
end

function ServerMonster:onAttacked(player, damage)
    if self.teamId == player.teamId then
        return false
    end
    if self.hp - damage <= 0 then
        self.hp = 0
    else
        self.hp = self.hp - damage
    end

    self.hp = self.hp - damage
    local yaw = player:getYaw()
    GamePacketSender:sendMonsterHP(self.entityId, self.hp)
    GamePacketSender:sendMonsterKnockBack(self.entityId, self.config.Repelled, yaw)
    if self.hp <= 0 then
        self:setDead()
    end
    return true
end